async def write_project(session, name: str, files: list, device: str = None) -> dict:
    if not isinstance(files, list) or not files:
        return {"error": "files must be a non-empty list of {path, content}"}
    written = [
        {"path": str(f["path"]).lstrip("/\\"), "content": f.get("content", "")}
        for f in files if f.get("path")
    ]
    results = await asyncio.gather(*(
        session.pc_exec("write_file", f"{name}/{w['path']}",
                        content=w["content"], device=device)
        for w in written
    ))
    for w, res in zip(written, results):
        if res.get("error"):
            return {"error": f"failed writing {name}/{w['path']}: {res['error']}"}
    await session.send({"type": "action", "action": "show_code",
                        "project": name, "files": written})
    return {"status": f"wrote {len(written)} files into the '{name}' project",
            "files": [w["path"] for w in written]}

