def _merge_tool_fragments(pending: dict[int, dict], fragments: list[dict]) -> None:
    for frag in fragments:
        slot = pending.setdefault(
            frag.get("index", 0), {"id": "", "name": "", "args": ""})
        if frag.get("id"):
            slot["id"] = frag["id"]
        fn = frag.get("function") or {}
        slot["name"] += fn.get("name", "")
        slot["args"] += fn.get("arguments", "")


def _drain_tool_calls(pending: dict[int, dict]):
    for slot in pending.values():
        if not slot["name"]:
            continue
        try:
            args = json.loads(slot["args"]) if slot["args"] else {}
        except json.JSONDecodeError:
            args = {}
        yield {"kind": "tool_call",
               "id": slot["id"] or f"call_{uuid.uuid4().hex[:8]}",
               "name": slot["name"], "args": args}

